import { describe, it, expect } from 'bun:test';
import {
  vickreyMoment,
  evaluatePhase,
  PulsePhase,
  isValidPulse3D,
  verifyTeleport,
  PELL_TOWER,
  TRIB_TOWER,
  CLOCK_MAX_INDEX,
  isSynchronized,
  snapToLattice,
} from './quasicrystalline-clock';
import { PISOT_FIB, pisotF } from './betti/pisot-primitive';

describe('Quasicrystalline Clock', () => {
  it('Pell and Tribonacci towers follow the correct recurrences', () => {
    // Pell: P[n+2] = 2P[n+1] + P[n]
    expect(PELL_TOWER[0]).toBe(1n);
    expect(PELL_TOWER[1]).toBe(2n);
    expect(PELL_TOWER[2]).toBe(5n);
    expect(PELL_TOWER[3]).toBe(12n);
    expect(PELL_TOWER[4]).toBe(29n);
    
    // Tribonacci: T[n+3] = T[n+2] + T[n+1] + T[n]
    expect(TRIB_TOWER[0]).toBe(1n);
    expect(TRIB_TOWER[1]).toBe(1n);
    expect(TRIB_TOWER[2]).toBe(2n);
    expect(TRIB_TOWER[3]).toBe(4n);
    expect(TRIB_TOWER[4]).toBe(7n);
  });

  it('Vickrey Moment (Clock Projection) matches Lean examples', () => {
    // Lean: cell3_0_0_0 = 1
    expect(vickreyMoment({ phi: 0, pell: 0, trib: 0 })).toBe(1n);
    
    // Lean: cell3_1_1_1 = 2
    expect(vickreyMoment({ phi: 1, pell: 1, trib: 1 })).toBe(2n);
    
    // Lean: cell3_3_2_3 = 60
    // F(3) = 3, P(2) = 5, T(3) = 4 => 3 * 5 * 4 = 60
    expect(vickreyMoment({ phi: 3, pell: 2, trib: 3 })).toBe(60n);
  });

  it('Cassini Parity Filter correctly identifies phases', () => {
    // Fibonacci: F(0)=1, F(1)=1, F(2)=2, F(3)=3, F(4)=5
    
    // Phase for n=1: F(0), F(1), F(2) => 1, 1, 2
    // F(2)*F(0) = 2*1 = 2; F(1)^2 + 1 = 1^2 + 1 = 2. => Even.
    expect(evaluatePhase({ prev: 1n, curr: 1n, next: 2n })).toBe(PulsePhase.Even);
    
    // Phase for n=2: F(1), F(2), F(3) => 1, 2, 3
    // F(3)*F(1) = 3*1 = 3; F(2)^2 = 2^2 = 4. => F(2)^2 = F(3)*F(1) + 1 => Odd.
    expect(evaluatePhase({ prev: 1n, curr: 2n, next: 3n })).toBe(PulsePhase.Odd);
    
    // Invalid pulse
    expect(evaluatePhase({ prev: 1n, curr: 1n, next: 1n })).toBe(PulsePhase.Invalid);
  });

  it('Lattice Teleportation (FORK verification) holds', () => {
    // localM=3, gapK=5. receivedNext = F(3+5+2) = F(10) = 89
    const localM = 3;
    const gapK = 5;
    const f10 = BigInt(pisotF(10));
    expect(verifyTeleport(localM, gapK, f10)).toBe(true);
    
    // Incorrect receivedNext
    expect(verifyTeleport(localM, gapK, 88n)).toBe(false);
  });

  it('3D Rejector correctly validates or rejects vector pulses', () => {
    const validPulse = {
      phi: { prev: 1n, curr: 1n, next: 2n }, // n=1, Even
      pell: { prev: 1n, curr: 2n, next: 5n }, // Pell n=1, Even
      trib: { prev: 1n, curr: 2n, next: 4n } // Trib n=2, Odd
    };
    
    const pulseWithInvalid = {
      ...validPulse,
      phi: { prev: 1n, curr: 1n, next: 3n } // Invalid
    };
    
    expect(isValidPulse3D(validPulse)).toBe(true);
    expect(isValidPulse3D(pulseWithInvalid)).toBe(false);
  });

  it('Topological Snapping correctly handles jitter within the Cassini gap', () => {
    const expected = 144n; // F(11)
    
    // Within the gap
    expect(isSynchronized(145n, expected)).toBe(true);
    expect(isSynchronized(143n, expected)).toBe(true);
    expect(isSynchronized(expected, expected)).toBe(true);
    
    // Outside the gap
    expect(isSynchronized(146n, expected)).toBe(false);
    expect(isSynchronized(142n, expected)).toBe(false);
    
    // Snapping
    expect(snapToLattice(145n, expected)).toBe(expected);
    expect(snapToLattice(143n, expected)).toBe(expected);
    expect(snapToLattice(146n, expected)).toBe(146n); // No snap
  });
});